def fibonacci(n):
    if n <= 2:              # base cases
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

for i in range(1, 8):
    print(fibonacci(i), end=" ")

exercises.solution:
def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n - 1)

print(factorial(6))

def fibonacci(n):
    if n <= 2:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(7))
